import{_ as p,o,c as a,ag as e}from"./chunks/framework.DlAClNku.js";const l="/The-Mythical-Man-Month-zh/assets/fg2-1.Ca-iyDhW.jpg",i="/The-Mythical-Man-Month-zh/assets/fg2-2.Cti37Gle.jpg",s="/The-Mythical-Man-Month-zh/assets/fg2-3.CDRutWym.jpg",h="/The-Mythical-Man-Month-zh/assets/fg2-4.Xj4pTQZd.jpg",n="/The-Mythical-Man-Month-zh/assets/fg2-5.BATuHtfb.jpg",c="/The-Mythical-Man-Month-zh/assets/fg2-4.Xj4pTQZd.jpg",r="/The-Mythical-Man-Month-zh/assets/fg2-7.iTGQEpj4.jpg",u="/The-Mythical-Man-Month-zh/assets/fg2-8.DtN5N6bU.jpg",f=JSON.parse('{"title":"第 2 章 人月神话（The Mythical Man-Month）","description":"","frontmatter":{},"headers":[],"relativePath":"ch2.md","filePath":"ch2.md","lastUpdated":1777274400000}'),q={name:"ch2.md"};function m(d,t,_,M,b,g){return o(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="第-2-章-人月神话-the-mythical-man-month" tabindex="-1">第 2 章 人月神话（The Mythical Man-Month） <a class="header-anchor" href="#第-2-章-人月神话-the-mythical-man-month" aria-label="Permalink to &quot;第 2 章 人月神话（The Mythical Man-Month）&quot;">​</a></h1><p>美酒的酿造需要年头，美食的烹调需要时间；片刻等待，更多美味，更多享受。</p><p>——新奥尔良 Antoine 餐厅的菜单</p><p>Good cooking takes time. If you are made to wait, it is to serve you better, and to please you.</p><p>——MENU OF RESTAURANT ANTOINE, NEW ORLEANS</p><p>在众多软件项目中，缺乏合理的时间进度是造成项目滞后的最主要原因，它比其他所有因素加起来的影响还要大。导致这种普遍性灾难的原因是什么呢？</p><p>首先，我们对估算技术缺乏有效的研究。更令人担忧的是，这背后其实有一个不言而喻却并不真实的假设——一切都将运作良好。</p><p>第二，我们采用的估算技术隐含地假设人和月可以互换，错误地将进度与工作量混为一谈。</p><p>第三，由于对自己的估算缺乏信心，软件经理通常不敢持续坚守自己的估算。</p><p>第四，对进度缺少跟踪和监督。其他工程领域中经过验证的跟踪技术和常规监督手段，在软件工程中常常被视为多余。</p><p>第五，当意识到进度偏移时，本能的（也是传统的）反应是增加人手。这无异于用汽油灭火，只会使事情更糟。越来越大的火势需要更多的汽油，由此陷入一场注定以灾难告终的循环。</p><p>进度监督将在另一篇论文中专门讨论，本章着重深入探讨其他几个方面。</p><h2 id="乐观主义" tabindex="-1">乐观主义 <a class="header-anchor" href="#乐观主义" aria-label="Permalink to &quot;乐观主义&quot;">​</a></h2><p>所有的程序员都是乐观主义者。也许是这种现代魔术格外吸引那些相信美好结局的人；也许是成百上千次琐碎的挫折将大多数人淘汰出局，只留下了那些习惯上只盯着最终结果的人；还有可能仅仅因为计算机还很年轻，程序员更加年轻，而年轻人总是乐观主义者——无论面对什么样的程序，结论都是毋庸置疑的：&quot;这次它肯定会运行&quot;，或者&quot;我刚刚找到了最后一个 bug&quot;。</p><p>因此，系统编程进度安排背后的第一个假设是：一切都将运作良好，每项任务仅花费它&quot;应该&quot;花费的时间。</p><p>程序员中弥漫的这种乐观主义，值得我们认真审视。Dorothy Sayers 在《创作者的心灵》（<em>The Mind of the Maker</em>）一书中，将创造性活动分为三个阶段：构思、实现和交流。一本书、一台计算机、或者一个程序，首先作为一个构思或模型出现在创造者的脑海中，与时间和空间无关；接着，借助钢笔、墨水和纸，或者电线、硅片和磁芯，在现实的时间和空间中被实现出来；最后，当某人阅读书本、使用计算机、运行程序时，他与创造者的思想相互沟通，创作过程由此完成。</p><p>正如 Sayers 所指出的，这一洞见不仅描述了人类的创造性活动，还与基督教关于三位一体的教义有异曲同工之妙，适用于一切人类创造性工作。对创造者而言，正是在实现的过程中，才能发现构思的不完整与不一致之处。因此，对于思考者来说，书写、实验以及&quot;付诸实践&quot;是不可或缺的。</p><p>在许多创造性活动中，驾驭实施的介质本身就是一大难题——木料、颜料、电线——这些物理介质的自然约束限制了思路的表达，也带来了许多意料之外的困难。</p><p>正是由于物理介质固有的局限性以及构思本身潜藏的缺陷，实际实现往往需要付出大量的时间与心血。</p><p>遇到实现上的困难时，我们总倾向于责怪那些物理介质——因为它们不肯顺从&quot;我们&quot;的构思。但这不过是我们的傲慢，让判断染上了主观色彩。</p><p>计算机编程的介质却截然不同——它极易驾驭。程序员通过纯粹的思维活动——概念和灵活的表达——来开发程序。正因为介质如此顺手，我们期望在实现过程中不会遭遇阻碍，乐观主义因此弥漫开来。然而，我们的构思本身是有缺陷的，bug 因此如影随形。换言之，我们并没有足够的理由如此乐观。</p><p>对于单个任务而言，&quot;一切都将运转正常&quot;的假设在进度上还具有一定的可行性——因为所遇到的延迟服从一个概率分布，&quot;完全不延迟&quot;只是其中有限概率的一种情形，现实中确实可能一切顺利。然而，大型编程工作包含众多任务，且任务之间往往存在先后依赖关系，&quot;一切正常&quot;的概率因此变得微乎其微，趋近于零。</p><h2 id="人月" tabindex="-1">人月 <a class="header-anchor" href="#人月" aria-label="Permalink to &quot;人月&quot;">​</a></h2><p>第二个谬误，体现在估算和进度安排所使用的工作量单位上：人月。成本确实会随人数和时间的不同而大幅变化，但进度并不如此。因此，我认为用人月来衡量一项工作的规模，是一个危险而具有欺骗性的神话。它暗示人员数量与时间可以相互替换。</p><p>人数与时间的互换只适用于一种情况：任务可以完全分解给各个参与者，且彼此之间无需任何沟通（图 2.1）。收割小麦或采摘棉花可以做到这一点，系统编程却几乎做不到。</p><p><img src="'+l+'" alt="人员和时间之间的关系——完全可以分解的任务"></p><blockquote><p>图 2.1：人员和时间之间的关系——完全可以分解的任务</p></blockquote><p>当任务因顺序约束而无法分解时，增加人手对进度毫无帮助（图 2.2）。无论多少位母亲，孕育一个生命都需要十个月。调试和测试的顺序依赖性，使许多软件工作都具有这一特征。</p><p><img src="'+i+'" alt="人员和时间之间的关系——无法分解的任务"></p><blockquote><p>图 2.2：人员和时间之间的关系——无法分解的任务</p></blockquote><p>对于可以分解、但子任务之间需要相互沟通的工作，计划时必须将沟通成本纳入考量。因此，在相同人月总量的前提下，以增加人手来缩短时间，最好的结果也比原来的安排要差（图 2.3）。</p><p><img src="'+s+'" alt="人员和时间之间的关系——需要沟通的可分解任务"></p><blockquote><p>图 2.3：人员和时间之间的关系——需要沟通的可分解任务</p></blockquote><p>沟通带来的额外负担由两部分组成：培训和相互协调。每位新成员都需要接受技术、项目目标和整体策略上的培训。培训无法分摊，因此这部分工作量随人员数量线性增长。</p><p>人员间的协调更为棘手。如果任务的每个部分都必须与其他部分单独对接，工作量将按 n(n-1)/2 增加。在一对一沟通的情况下，三个人的沟通量是两个人的三倍，四个人则是两个人的六倍。若还需要三四个人共同开会、协商、联合解决问题，情况会更糟。新增的沟通工作量可能完全抵消任务分解带来的收益，将我们拖入图 2.4 所示的境地。</p><p><img src="'+h+'" alt="人员和时间之间的关系——关系错综复杂的任务"></p><blockquote><p>图 2.4：人员和时间之间的关系——关系错综复杂的任务</p></blockquote><p>软件开发本质上是一项系统工程——在错综复杂的相互依存关系中展开。沟通协调的工作量极大，很快就会吞噬掉任务分解节省的个人时间。结果是，增加更多人手，实际上延长了而非缩短了工期。</p><h2 id="系统测试" tabindex="-1">系统测试 <a class="header-anchor" href="#系统测试" aria-label="Permalink to &quot;系统测试&quot;">​</a></h2><p>在时间进度中，顺序约束的影响，在单元调试和系统测试阶段体现得最为彻底。所需时间还取决于遇到的错误和缺陷数量，以及发现它们的难易程度。理论上，缺陷数量应为零。但由于我们的乐观主义，实际出现的缺陷往往远超预期。因此，系统测试的进度安排，常常是整个编程计划中最不合理的部分。</p><p>对于软件任务的进度安排，以下是我沿用多年的经验法则：</p><ul><li>1/3 计划</li><li>1/6 编码</li><li>1/4 构件测试和早期系统测试</li><li>1/4 系统测试（所有构件已完成）</li></ul><p>这与传统的进度安排方式有几处重要的不同：</p><ol><li>分配给计划的时间比通常要多。即便如此，仍不足以产生详细、稳定的规格说明，也不足以为探索全新技术留出空间。</li><li>调试和测试占据了将近一半的时间，远超一般安排。</li><li>最容易估计的部分——编码——只分配了六分之一的时间。</li></ol><p>通过研究传统项目的进度安排，我发现很少有项目愿意为测试分配一半的时间，但大多数项目的测试实际上就花了这么长时间。其中许多项目在系统测试之前尚能保持进度，一旦进入系统测试阶段便开始失控。</p><p>特别需要指出的是，不为系统测试留出足够时间，几乎是灾难的同义词。延迟偏偏发生在项目快要收尾之时，直到发布日期临近，才有人发现进度失控的问题。于是，坏消息毫无预兆地出现在客户和项目经理面前。</p><p>更糟糕的是，这一阶段的延迟会引发严重的财务和心理连锁反应。项目此时已经满员运转，每日人力成本已达到最高峰。如果软件还要支撑其他商业活动（例如硬件交付、新系统上线），这些后续活动因此推迟，代价将极为高昂。</p><p>事实上，这些二次损失往往远超直接开销。因此，在早期制订计划时，为系统测试留足充裕的时间至关重要。</p><h2 id="空泛的估算" tabindex="-1">空泛的估算 <a class="header-anchor" href="#空泛的估算" aria-label="Permalink to &quot;空泛的估算&quot;">​</a></h2><p>观察程序员，你会发现他们和厨师一样：某项任务的计划进度，可能会受到顾客要求期限的压缩，但紧迫程度无法左右实际的完成情况。就好比约定两分钟内煎好一个鸡蛋——看上去似乎可行，但若两分钟到了蛋还没熟，顾客只能等待，或者生吃。软件顾客的处境与此相似。</p><p>厨师还有另一条路：把火开大。结果往往是无法&quot;挽救&quot;的鸡蛋——一面焦糊，另一面还是生的。</p><p>我并不认为软件经理在勇气和坚持上天生不如厨师，或不如其他工程经理。但在软件领域，为了迎合顾客期望的日期而制订不合理的进度，远比其他任何工程领域更为普遍。更何况，缺乏阶段化的方法，数据支撑少得可怜，完全依赖软件经理的直觉拍板——如此方式，很难产出稳健可靠、能够规避风险的估算。</p><p>解决之道有两条。其一，开发并推广生产率数据、缺陷率统计、估算规则等，让整个组织共享这些数据的积累与收益。</p><p>其二，在可靠的估算基础建立之前，项目经理需要挺直腰杆，坚守自己的估算，相信自身的经验与直觉，远比从&quot;期望&quot;倒推出来的结论可靠得多。</p><h2 id="重复产生的进度灾难" tabindex="-1">重复产生的进度灾难 <a class="header-anchor" href="#重复产生的进度灾难" aria-label="Permalink to &quot;重复产生的进度灾难&quot;">​</a></h2><p>当一个软件项目落后于进度时，通常的做法是加派人手。如图 2.1 至 2.4 所示，这有时有效，有时无济于事。</p><p>我们来看一个例子。设想一项估计需要 12 个人月的任务，分配给 3 名成员，计划用 4 个月完成，在每个月末安排了可度量的里程碑 A、B、C、D（图 2.5）。</p><p>现在假设两个月后，第一个里程碑未能达到（图 2.6）。项目经理有哪些选择？</p><ol><li>假设任务必须按时完成，且只有第一部分估计有误（如图 2.6 所示）。那么剩余工作量为 9 个人月，剩余时间 2 个月，需要 4.5 名开发人员，即在原来 3 人的基础上再增加 2 人。</li><li>假设任务必须按时完成，且整体估算都偏低（如图 2.7 所示）。那么剩余工作量为 18 个人月，剩余时间 2 个月，需要将团队从 3 人扩充到 9 人。</li><li>重新安排进度。我赞同 P. Fagg 的忠告——这位经验丰富的硬件工程师说：&quot;不要容忍小的偏差（Take no small slips）&quot;。也就是说，在新的进度表中分配足够的时间，确保工作能仔细彻底地完成，从而不必再次调整时间表。</li><li>削减任务。在现实中，一旦开发团队发现进度偏差，往往倾向于砍掉任务。当延期的后续代价极高时，这有时是唯一可行的办法。项目经理的选择是：要么郑重正式地裁减项目范围并调整进度；要么默默看着任务项因仓促的设计和不完整的测试而悄悄缩水。</li></ol><p><img src="'+n+'" alt=""></p><blockquote><p>图 2.5</p></blockquote><p><img src="'+c+'" alt=""></p><blockquote><p>图 2.6</p></blockquote><p><img src="'+r+'" alt=""></p><blockquote><p>图 2.7</p></blockquote><p><img src="'+u+'" alt=""></p><blockquote><p>图 2.8</p></blockquote><p>在前两种情况中，坚持在不调整计划的前提下按原期限完成任务，将是灾难性的。以第一种情况为例（图 2.8）：不管在多短的时间内招来多能干的两位新人，他们都需要由一位老手来培训。若培训需要一个月，就有三个人月被额外占用。原先划分为三份的工作，现在要重新分成五份；部分已完成的工作必然需要返工，系统测试也必须延长。到第三个月末，仍有 7 个人月的工作量，但只有 5 个有效人月可用。如图 2.8 所示，产品照样会延期——和没有增加任何人手的情况（图 2.6）相差无几。</p><p>若还想在四个月内完成，光是计入培训时间（还没算任务重新划分和额外系统测试），第二个月末就需要增加 4 人而非 2 人。若再把任务重组和系统测试的工作量算进去，还需继续增员。届时拥有的已不是 3 人团队，而是 7 人以上的队伍；小组的组织方式和任务划分都将发生质的变化，而非程度上的调整。</p><p>注意，到第三个月末，局面看起来依然一团糟。撇开管理开销不谈，3 月 1 日的里程碑仍未达到。此刻，项目经理面临着强烈的诱惑——继续增加人手，结果往往是上述循环的再次上演。这无异于饮鸩止渴。</p><p>以上讨论还只是第一个里程碑估计不当的情形。如果到 3 月 1 日，项目经理做出更悲观的判断——整体估算都过于乐观（如图 2.7 所示），则需要再增加 6 名人手。培训、任务重新分配、系统测试工作量的推算，留给读者作为练习。但毫无疑问，这种&quot;救火式&quot;扩员所交付的产品，将比不加人手、重新制订进度所交付的产品更差。</p><p>简单而直接地重申布鲁克斯法则：</p><blockquote><p><strong>向进度落后的项目中增加人手，只会使进度更加落后。</strong>（Adding manpower to a late software project makes it later.）</p></blockquote><p>这就是人月神话的真相。项目工期取决于顺序上的约束，所需人手取决于各个子任务的数量。由这两个因素推导出的进度表，安排的人员较少、时间较长（唯一的风险是产品可能过时）。反过来，配置更多人手、压缩时间，只会得到一张无法落地的进度表。总之，在众多软件项目中，缺乏合理的时间进度是造成项目滞后的最主要原因，其影响超过其他所有因素之和。</p>',74)])])}const T=p(q,[["render",m]]);export{f as __pageData,T as default};
